"use client";

import { useEffect, useState } from "react";
import { PurchaseOrder } from "@/types";
import { getPurchaseOrders, updatePOStatus } from "@/lib/purchaseOrders";
import { formatCurrency } from "@/lib/currencies";
import { useModal } from "@/context/ModalContext";
import { useAuth } from "@/context/AuthContext";

export default function PurchaseOrdersPage() {
    const { user } = useAuth();
    const { showConfirm, showAlert, showError } = useModal();
    const [pos, setPos] = useState<PurchaseOrder[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchData = () => getPurchaseOrders().then(data => {
        setPos(data.sort((a, b) => b.issuedAt.getTime() - a.issuedAt.getTime()));
        setLoading(false);
    });

    useEffect(() => {
        fetchData();
    }, []);

    const handleReceive = async (id: string, poNumber: string) => {
        const confirmed = await showConfirm(
            "Confirm Receipt",
            `Mark ${poNumber} as Received? This confirms all items have been delivered.`
        );
        if (!confirmed) return;

        try {
            await updatePOStatus(id, 'RECEIVED');
            await showAlert("Success", "Goods Receipt Confirmed");
            fetchData(); // Changed function name to match logic
        } catch (error) {
            await showError("Error", "Error updating status");
        }
    };

    if (loading) return <div>Loading Purchase Orders...</div>;

    return (
        <div>
            <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', marginBottom: '2rem', color: 'var(--primary)' }}>Purchase Orders</h1>

            {pos.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>No Purchase Orders issued yet.</p>
                </div>
            ) : (
                <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead style={{ backgroundColor: 'var(--background)', borderBottom: '1px solid var(--border)' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>PO Number</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Date Issued</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Vendor</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Total</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Status</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {pos.map((po) => (
                                <tr key={po.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>{po.poNumber}</td>
                                    <td style={{ padding: '1rem' }}>{po.issuedAt.toLocaleDateString()}</td>
                                    <td style={{ padding: '1rem' }}>{po.vendorName}</td>
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>{formatCurrency(po.totalAmount, po.currency)}</td>
                                    <td style={{ padding: '1rem' }}>
                                        <span style={{
                                            padding: '0.25rem 0.5rem',
                                            borderRadius: '999px',
                                            fontSize: '0.75rem',
                                            backgroundColor: po.status === 'ISSUED' ? '#eff6ff' : po.status === 'RECEIVED' ? '#dcfce7' : '#f3f4f6',
                                            color: po.status === 'ISSUED' ? '#1e40af' : po.status === 'RECEIVED' ? '#166534' : '#4b5563'
                                        }}>
                                            {po.status}
                                        </span>
                                    </td>
                                    <td style={{ padding: '1rem' }}>
                                        {po.status === 'ISSUED' && po.id ? (
                                            <button
                                                onClick={() => po.id && handleReceive(po.id, po.poNumber)}
                                                style={{ color: 'var(--success)', background: 'none', border: '1px solid var(--success)', padding: '0.25rem 0.5rem', borderRadius: '4px', cursor: 'pointer', fontSize: '0.8rem' }}
                                            >
                                                Receive Goods
                                            </button>
                                        ) : (
                                            <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                                                {po.status === 'RECEIVED' ? 'Received' : 'View'}
                                            </span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}
